class _Node:
    __slots__ = ("val", "left", "right")
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None


def _build(values):
    if not values or values[0] is None:
        return None
    root = _Node(values[0])
    queue = [root]
    i = 1
    while queue and i < len(values):
        node = queue.pop(0)
        if i < len(values):
            v = values[i]
            i += 1
            if v is not None:
                node.left = _Node(v)
                queue.append(node.left)
        if i < len(values):
            v = values[i]
            i += 1
            if v is not None:
                node.right = _Node(v)
                queue.append(node.right)
    return root


def _invert(node):
    if node is None:
        return None
    node.left, node.right = _invert(node.right), _invert(node.left)
    return node


def _serialize(root):
    if root is None:
        return []
    out = []
    queue = [root]
    while queue:
        node = queue.pop(0)
        if node is None:
            out.append(None)
            continue
        out.append(node.val)
        queue.append(node.left)
        queue.append(node.right)
    while out and out[-1] is None:
        out.pop()
    return out


def invert_tree(values):
    root = _build(values)
    root = _invert(root)
    return _serialize(root)
